app.post('/api/translate', async (req, res) => {
  const { text, targetLang, sourceLang } = req.body;
  if (!text || !targetLang) return res.json({ success: false, error: 'Missing text or target language' });
  if (targetLang === 'en' && (!sourceLang || sourceLang === 'en')) return res.json({ success: true, translated: text, receipt: { tokens_in: 0, tokens_out: 0, governed: true } });
  
  const startTime = Date.now();
  try {
    const langNames = {en:'English',es:'Spanish',bzj:'Belizean Kriol',fr:'French',pt:'Portuguese',zh:'Mandarin Chinese',ar:'Arabic',ht:'Haitian Creole',tl:'Tagalog',vi:'Vietnamese',ko:'Korean',ja:'Japanese',de:'German',it:'Italian',ru:'Russian',sw:'Swahili',hi:'Hindi',ur:'Urdu'};
    const targetName = langNames[targetLang] || targetLang;
    const sourceName = langNames[sourceLang] || 'auto-detect';
    
    const tRes = await axios.post('https://api.anthropic.com/v1/messages', {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 800,
      system: 'You are a governed translation engine. Translate the text accurately. Preserve meaning, tone, and domain-specific terminology. Return ONLY the translated text with no preamble, no explanation, no quotes.',
      messages: [{ role: 'user', content: 'Translate from ' + sourceName + ' to ' + targetName + ':\n\n' + text }]
    }, {
      headers: { 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' }
    });
    
    const translated = tRes.data.content.map(c => c.text || '').join('').trim();
    const tokensIn = tRes.data.usage ? tRes.data.usage.input_tokens : 0;
    const tokensOut = tRes.data.usage ? tRes.data.usage.output_tokens : 0;
    const duration = Date.now() - startTime;
    
    // Log translation as governed inference
    try {
      await pool.query('INSERT INTO audit_log (table_name, action_type, changed_by, new_value) VALUES ($1,$2,$3,$4)',
        [TABLE_NAME, 'TRANSLATION', 'International Mode', JSON.stringify({source_lang: sourceLang || 'auto', target_lang: targetLang, tokens_in: tokensIn, tokens_out: tokensOut, duration_ms: duration})]);
    } catch(e) {}
    
    res.json({ success: true, translated, receipt: { tokens_in: tokensIn, tokens_out: tokensOut, duration_ms: duration, source_lang: sourceLang || 'auto', target_lang: targetLang, governed: true }});
  } catch (err) {
    res.json({ success: false, error: err.message });
  }
});

